mapper.select:
SELECT ZONE_ID, ZONE_CD, ZONE_NM FROM TBL_WH_ZONE_M WHERE USE_YN = 'Y' AND DELETED_YN = 'N' AND WH_CD = 'WH01'
AND CMPY_CD = #{cmpyCd}
ORDER BY VIEW_SEQ

mapper.insert:
MERGE INTO sonictmsdev_mssql.dbo.TBL_STOCK AS target USING ( SELECT CAST(#{cmpyCd, jdbcType=VARCHAR} AS VARCHAR(10)) as cmpyCd, CAST(#{agntCd, jdbcType=VARCHAR} AS VARCHAR(20)) as agntCd, CAST(#{whCd, jdbcType=VARCHAR} AS VARCHAR(20)) as whCd, CAST(#{mtrlCd, jdbcType=VARCHAR} AS VARCHAR(100)) as mtrlCd, CAST(#{zoneId, jdbcType=BIGINT} AS BIGINT) as zoneId, CAST(#{locId, jdbcType=BIGINT} AS BIGINT) as locId, CAST(#{lotNo, jdbcType=VARCHAR} AS VARCHAR(50)) as lotNo ) AS source ON ( target.CMPY_CD = source.cmpyCd AND target.LOC_ID = source.locId AND target.MTRL_CD = source.mtrlCd AND ISNULL(target.LOT_NO, '') = ISNULL(source.lotNo, '') )
WHEN MATCHED THEN UPDATE SET STOCK_QTY = target.STOCK_QTY + #{putawayQty, jdbcType=INTEGER}, UPDT_TIME = GETDATE(), UPDT_USER = #{putawayUser, jdbcType=VARCHAR}
WHEN NOT MATCHED THEN INSERT ( CMPY_CD, AGNT_CD, WH_CD, MTRL_CD, ZONE_ID, LOC_ID, LOT_NO, EXPIRE_DATE, STOCK_QTY, UPDT_TIME, UPDT_USER ) VALUES ( source.cmpyCd, source.agntCd, source.whCd, source.mtrlCd, source.zoneId, source.locId, source.lotNo, #{expireDate, jdbcType=DATE}, #{putawayQty, jdbcType=INTEGER}, GETDATE(), #{putawayUser, jdbcType=VARCHAR} );

mapper.select:
SELECT
    ZONE_ID  AS zoneId,
    LOC_ID   AS locId,
    LOC_CD   AS locCd,
    WH_CD    AS whCd
FROM TBL_WH_LOC_M
WHERE CMPY_CD     = #{cmpyCd}
  AND ZONE_ID     = #{zoneId}
  AND LOC_CD = #{locBarcode}
  AND DELETED_YN  = 'N'
